class Solution {
    public boolean isPalindrome(String originalPhrase) {
        // Create a reversed version of the original phrase.
        StringBuilder reversedPhraseBuilder = new StringBuilder(originalPhrase).reverse();
        String reversedPhrase = reversedPhraseBuilder.toString();

        // Compare the original phrase with the reversed phrase character by character.
        // This step is crucial to ensure exact matching for palindrome verification.
        if (originalPhrase.length() != reversedPhrase.length()) {
            return false;
        }

        // If any character mismatch is found, it's not a palindrome.
        for (int characterIndex = 0; characterIndex < originalPhrase.length(); characterIndex++) {
            if (originalPhrase.charAt(characterIndex) != reversedPhrase.charAt(characterIndex)) {
                return false;
            }
        }

        // If all characters match, the phrase is a palindrome.
        return true;
    }
}

