func isPalindrome(inputString string) bool {
	leftPointer := 0
	rightPointer := len(inputString) - 1

	// Continue as long as the left pointer is to the left of the right pointer.
	for leftPointer < rightPointer {
		// Advance the left pointer past non-alphanumeric characters.
		for leftPointer < rightPointer && !unicode.IsLetter(rune(inputString[leftPointer])) && !unicode.IsNumber(rune(inputString[leftPointer])) {
			leftPointer++
		}

		// Advance the right pointer past non-alphanumeric characters.
		for leftPointer < rightPointer && !unicode.IsLetter(rune(inputString[rightPointer])) && !unicode.IsNumber(rune(inputString[rightPointer])) {
			rightPointer--
		}

		// Compare characters after converting them to lowercase for case-insensitive comparison.
		if strings.ToLower(string(inputString[leftPointer])) != strings.ToLower(string(inputString[rightPointer])) {
			// If characters do not match, it is not a palindrome.
			return false
		}

		// Move pointers inward to check the next pair of characters.
		leftPointer++
		rightPointer--
	}

	// If the loop completes without finding mismatches, the string is a palindrome.
	return true
}

