func isPalindrome(_ phrase: String) -> Bool {
    var startPointerIndex = phrase.startIndex
    var endPointerIndex = phrase.endIndex

    // Convert the phrase to lowercase to ensure case-insensitive comparison.
    let lowercasedPhrase = phrase.lowercased()

    // Continue as long as the start pointer is before the end pointer.
    while startPointerIndex < endPointerIndex {
        let startCharacter = lowercasedPhrase[startPointerIndex]
        let endCharacter = lowercasedPhrase[endPointerIndex]

        // Skip non-alphanumeric characters from the start.
        if !startCharacter.isLetter && !startCharacter.isNumber {
            // Move the start pointer forward if the character is not relevant.
            let nextStart = lowercasedPhrase.index(after: startPointerIndex)
            if nextStart < endPointerIndex {
                startPointerIndex = nextStart
            } else {
                break
            }
            continue
        }

        // Skip non-alphanumeric characters from the end.
        if !endCharacter.isLetter && !endCharacter.isNumber {
            // Move the end pointer backward if the character is not relevant.
            let previousEnd = lowercasedPhrase.index(before: endPointerIndex)
            if startPointerIndex < previousEnd {
                endPointerIndex = previousEnd
            } else {
                break
            }
            continue
        }

        // Compare the characters at the current pointers.
        if startCharacter != endCharacter {
            // If characters don't match, it's not a palindrome.
            return false
        }

        // Move both pointers inwards.
        let nextStart = lowercasedPhrase.index(after: startPointerIndex)
        let previousEnd = lowercasedPhrase.index(before: endPointerIndex)

        // Ensure pointers don't cross if they are the same character.
        if nextStart >= previousEnd {
            break
        }

        startPointerIndex = nextStart
        endPointerIndex = previousEnd
    }

    // If the loop completes without finding mismatches, it's a palindrome.
    return true
}
